// Create an OrderBuilder in a shared test helpers file
public class OrderBuilder
{
    private string _customerId = "C001";
    private string _customerEmail = "alice@example.com";
    private bool _isPremium = false;
    private List<OrderItem> _items = new();

    public OrderBuilder WithCustomerId(string id) { _customerId = id; return this; }
    public OrderBuilder WithEmail(string email) { _customerEmail = email; return this; }
    public OrderBuilder WithPremium(bool premium) { _isPremium = premium; return this; }
    public OrderBuilder AddItem(string productId, string name, int qty, decimal price)
    {
        _items.Add(new OrderItem { ProductId = productId, Name = name, Quantity = qty, UnitPrice = price });
        return this;
    }
    public Order Build() => new() { CustomerId = _customerId, CustomerEmail = _customerEmail, 
                                     IsPremium = _isPremium, Items = _items };
}

// Usage:
var order = new OrderBuilder()
    .WithCustomerId("C001")
    .WithEmail("alice@example.com")
    .AddItem("P1", "Widget", 2, 9.99m)
    .Build();
```

